import { Terminal } from "xterm";
import { availableCommandsPrompt, messages } from "./messages";
export default class eXTerm extends Terminal {
    constructor(options) {
        super(options);
        this.prompt = "$ ";
        this.executeCommand = (command = this.command) => {
            this.print(messages.get(command));
            this.clearCommand();
        };
        this.displayErrorMessage = () => {
            this.print(availableCommandsPrompt);
            this.clearCommand();
        };
        this.print = async (message) => {
            const shouldAddExtraLine = this.buffer.active.cursorX > 0;
            const toWrite = `${shouldAddExtraLine ? "\r\n" : ""}${message}\r\n${this.prompt}`;
            for (const c of toWrite) {
                this.write(c);
                await new Promise(resolve => setTimeout(resolve, 1));
            }
        };
        this.addCharToCommand = (key) => {
            this._command += key;
            this.write(key);
        };
        this.clearCommand = () => {
            this.history.push(this.command);
            this._command = "";
        };
        this.backspace = () => {
            if (this.command) {
                this._command = this.command.slice(0, -1);
                this.write("\b \b");
            }
        };
        this._command = "";
        this.history = [];
    }
    get command() {
        return this._command;
    }
}
