import zip from "lodash.zip";
export const destinations = ["/", "/about", "/contact", "/portfolio"];
export const labels = ["home", "about", "contact", "portfolio"];
const labelMap = new Map(zip(destinations, labels));
const pathMap = new Map(zip(labels, destinations));
export const toLabel = (path) => labelMap.get(path);
export const toPath = (label) => pathMap.get(label);
