<script lang="ts">
  import { FitAddon } from "xterm-addon-fit";
  import { WebLinksAddon } from "xterm-addon-web-links";
  import "xterm/css/xterm.css";
  import Theme from "./TerminalTheme";

  import { onMount } from "svelte";
  import { watchResize } from "svelte-watch-resize";
  import { navigate } from "svelte-routing";

  import eXTerm from "./eXTerm";
  import { currentCommand } from "@src/stores";
  import { labels, toPath } from "@src/utils";

  const term = new eXTerm({
    fontFamily: "cascadia code",
    fontSize: 20,
    cursorBlink: true,
    cursorStyle: "underline",
    theme: Theme,
  });

  const fitAddon = new FitAddon();
  const webLinksAddon = new WebLinksAddon();

  onMount(() => {
    term.open(document.getElementById("terminal"));
    term.loadAddon(fitAddon);
    term.loadAddon(webLinksAddon);

    term.onKey(({ key }) => {
      switch (key.charCodeAt(0)) {
        case 13:
          const { command } = term;

          if ($currentCommand === command) {
            term.executeCommand();
            return;
          }

          if (!labels.includes(command)) {
            term.displayErrorMessage();
            return;
          }

          navigate(toPath(command));
          return;
        case 127:
          term.backspace();
          return;
        default:
          term.addCharToCommand(key);
          return;
      }
    });
  });

  $: term.executeCommand($currentCommand);
</script>

<div id="terminal" use:watchResize={() => fitAddon.fit()} />
