	import TabbedTerminal from "./components/Terminal/TabbedTerminal.svelte";

	import { currentCommand } from "@src/stores";
	import { toLabel } from "./utils";

	globalHistory.listen(({ location: { pathname } }) => currentCommand.set(toLabel(pathname)));
</script>

